const places = $('Fetch Google Places Data').first().json;
const internal = $('Fetch Internal Metrics').first().json;

// --- Scoring Rubric (100 points) ---
let score = 0;
const breakdown = {};

// 1. Posts (25 pts) — based on posts in last 30 days
const postCount = internal?.post_count_30d || 0;
if (postCount >= 12) breakdown.posts = 25;
else if (postCount >= 8) breakdown.posts = 20;
else if (postCount >= 4) breakdown.posts = 15;
else if (postCount >= 1) breakdown.posts = 8;
else breakdown.posts = 0;

// 2. Reviews (20 pts) — total review count
const reviewCount = places?.userRatingCount || 0;
if (reviewCount >= 100) breakdown.reviews = 20;
else if (reviewCount >= 50) breakdown.reviews = 16;
else if (reviewCount >= 25) breakdown.reviews = 12;
else if (reviewCount >= 10) breakdown.reviews = 8;
else breakdown.reviews = Math.min(reviewCount, 4);

// 3. Rating (15 pts)
const rating = places?.rating || 0;
if (rating >= 4.8) breakdown.rating = 15;
else if (rating >= 4.5) breakdown.rating = 12;
else if (rating >= 4.0) breakdown.rating = 9;
else if (rating >= 3.5) breakdown.rating = 5;
else breakdown.rating = 0;

// 4. Photos (15 pts)
const photoCount = places?.photos?.length || 0;
if (photoCount >= 20) breakdown.photos = 15;
else if (photoCount >= 10) breakdown.photos = 12;
else if (photoCount >= 5) breakdown.photos = 8;
else if (photoCount >= 1) breakdown.photos = 4;
else breakdown.photos = 0;

// 5. FAQ Freshness (15 pts) — days since last FAQ rotation
const lastFaqDate = internal?.last_faq_rotation;
let faqDaysAgo = 999;
if (lastFaqDate) faqDaysAgo = Math.floor((Date.now() - new Date(lastFaqDate).getTime()) / 86400000);
if (faqDaysAgo <= 90) breakdown.faq_freshness = 15;
else if (faqDaysAgo <= 180) breakdown.faq_freshness = 10;
else if (faqDaysAgo <= 365) breakdown.faq_freshness = 5;
else breakdown.faq_freshness = 0;

// 6. Hours (10 pts) — assumed up-to-date if profile exists
breakdown.hours = places?.rating ? 10 : 0;

// Total
for (const key of Object.keys(breakdown)) score += breakdown[key];

// Grade
let grade;
if (score >= 90) grade = 'A';
else if (score >= 80) grade = 'B';
else if (score >= 70) grade = 'C';
else if (score >= 60) grade = 'D';
else grade = 'F';

// Recommendations
const recs = [];
if (breakdown.posts < 20) recs.push('Increase GBP posting frequency (target: 3+/week)');
if (breakdown.reviews < 16) recs.push('Run a review request campaign to boost count');
if (breakdown.rating < 12) recs.push('Address negative reviews to improve rating');
if (breakdown.photos < 12) recs.push('Add more photos: before/after, team, equipment');
if (breakdown.faq_freshness < 15) recs.push('Run FAQ rotation — content is stale');
if (breakdown.hours < 10) recs.push('Verify business hours are accurate on GBP');

return [{ json: { score, grade, breakdown, review_count: reviewCount, review_rating: rating, post_count_30d: postCount, photo_count: photoCount, recommendations: recs } }];
